INSERT INTO `integrations` VALUES (1,'Beamer','Announce updates and get feedback with in-app notification center, widgets and changelog','/img/integrations/Beamer.svg','',1,1),(2,'Getsitecontrol','It helps you prevent website visitors from leaving your website without taking any action.','/img/integrations/Getsitecontrol.svg','',1,1),(3,'Google Analytics','Statistics and basic analytical tools for search engine optimization (SEO) and marketing purposes','/img/integrations/Google%20Analytics.svg','',1,1),(4,'Google Tag manager','Manage all your website tags without editing the code using simple tag management solutions','/img/integrations/Google%20Tag%20manager.svg','<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-9EK7SJG6LW\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-9EK7SJG6LW\');\r\n</script>',1,2),(5,'JivoChat','All-in-one business messenger to talk to customers: live chat, phone, email and social','/img/integrations/JivoChat.svg','',1,1),(6,'Onesignal','Leader in customer engagement, empowers mobile push, web push, email, in-app messages','/img/integrations/Onesignal.svg','',1,1),(7,'Push alert','Increase reach, revenue, retarget users with Push Notifications on desktop and mobile','/img/integrations/Push%20alert.svg','<div class=\"tamim_backdrop\" id=\"tamimBackdrop\">\r\n  <div class=\"tamim_box\">\r\n    <button class=\"tamim_close\" id=\"tamimClose\">×</button>\r\n    <h2>বিশেষ সতর্কতা নোটিশ</h2>\r\n    <p>বর্তমানে মার্কেটে অনেক কম দামী সার্ভিস এসেছে। এই সার্ভিসগুলো ব্যবহারের ক্ষেত্রে সতর্ক থাকুন এবং একবারে বড় অ্যামাউন্ট অর্ডার না করে অল্প অল্প করে অর্ডার সম্পন্ন করুন।</p>\r\n    \r\n    <p class=\"promo-text\">নতুন অফার, সার্ভিস আপডেট ও স্পেশাল ডিসকাউন্ট পেতে এখনই Join করুন!</p>\r\n    \r\n    <div class=\"button-group\">\r\n      <a href=\"https://whatsapp.com/channel/0029Vb66ocgCRs1f7CSK7d3k\" target=\"_blank\" class=\"popup-button whatsapp\">\r\n        <i class=\"fab fa-whatsapp\"></i> WhatsApp\r\n      </a>\r\n      \r\n      <a href=\"https://t.me/smmmarkets_com\" target=\"_blank\" class=\"popup-button telegram\">\r\n        <i class=\"fab fa-telegram\"></i> Telegram\r\n      </a>\r\n    </div>\r\n    </div>\r\n</div>\r\n\r\n<style>\r\n  /* মেইন ব্যাকড্রপ */\r\n  .tamim_backdrop {\r\n    position: fixed;\r\n    inset: 0;\r\n    background: rgba(0,0,0,0.6);\r\n    display: none;\r\n    align-items: center;\r\n    justify-content: center;\r\n    z-index: 9999;\r\n    padding: 20px;\r\n    font-family: \'Segoe UI\', Tahoma, Geneva, Verdana, sans-serif;\r\n  }\r\n\r\n  /* পপআপ বক্স */\r\n  .tamim_box {\r\n    position: relative;\r\n    width: 100%;\r\n    max-width: 450px;\r\n    border-radius: 15px;\r\n    background: #ffffff !important;\r\n    padding: 30px 25px;\r\n    box-shadow: 0 15px 40px rgba(0,0,0,0.4);\r\n    text-align: center;\r\n    animation: tamim-pop-in 0.3s ease-out;\r\n  }\r\n\r\n  @keyframes tamim-pop-in {\r\n    from { transform: scale(0.9); opacity: 0; }\r\n    to { transform: scale(1); opacity: 1; }\r\n  }\r\n\r\n  .tamim_box h2 {\r\n    font-size: 22px;\r\n    color: #d32f2f; /* লাল রঙ সতর্কতার জন্য */\r\n    margin-bottom: 12px;\r\n    font-weight: 700;\r\n  }\r\n\r\n  .tamim_box p {\r\n    color: #333333 !important;\r\n    font-size: 15px;\r\n    line-height: 1.5;\r\n    margin-bottom: 15px;\r\n  }\r\n\r\n  .promo-text {\r\n    font-weight: 600;\r\n    color: #1a237e !important;\r\n    margin-top: 15px !important;\r\n    border-top: 1px dashed #ccc;\r\n    padding-top: 15px;\r\n  }\r\n\r\n  /* বাটন স্টাইল */\r\n  .button-group {\r\n    display: flex;\r\n    gap: 10px;\r\n    justify-content: center;\r\n    margin-top: 20px;\r\n  }\r\n\r\n  .popup-button {\r\n    text-decoration: none;\r\n    padding: 10px 20px;\r\n    border-radius: 8px;\r\n    color: white !important;\r\n    font-weight: 600;\r\n    font-size: 14px;\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 8px;\r\n    transition: 0.3s;\r\n  }\r\n\r\n  .whatsapp { background: #25D366; }\r\n  .whatsapp:hover { background: #128C7E; }\r\n\r\n  .telegram { background: #0088cc; }\r\n  .telegram:hover { background: #006699; }\r\n\r\n  /* ক্লোজ বাটন */\r\n  .tamim_close {\r\n    position: absolute;\r\n    right: 12px;\r\n    top: 10px;\r\n    border: none;\r\n    background: none;\r\n    color: #999;\r\n    font-size: 28px;\r\n    cursor: pointer;\r\n    line-height: 1;\r\n  }\r\n</style>\r\n\r\n<script>\r\n  (function () {\r\n    var backdrop = document.getElementById(\'tamimBackdrop\');\r\n    var closeBtn = document.getElementById(\'tamimClose\');\r\n    var SHOW_DELAY_MS = 500; \r\n    \r\n    var refreshCount = localStorage.getItem(\'tamim_refresh_count\') || 0;\r\n    var isClosed = localStorage.getItem(\'tamim_popup_closed\');\r\n\r\n    function openPopup() {\r\n      if (isClosed !== \'true\' || parseInt(refreshCount) >= 3) {\r\n        if(backdrop) {\r\n            backdrop.style.display = \'flex\';\r\n            localStorage.setItem(\'tamim_refresh_count\', 0);\r\n            localStorage.removeItem(\'tamim_popup_closed\');\r\n        }\r\n      }\r\n    }\r\n\r\n    function closePopup() {\r\n      if(backdrop) {\r\n        backdrop.style.display = \'none\';\r\n        localStorage.setItem(\'tamim_popup_closed\', \'true\');\r\n        localStorage.setItem(\'tamim_refresh_count\', 0);\r\n      }\r\n    }\r\n\r\n    if (isClosed === \'true\') {\r\n        localStorage.setItem(\'tamim_refresh_count\', parseInt(refreshCount) + 1);\r\n    }\r\n\r\n    if(closeBtn) closeBtn.addEventListener(\'click\', closePopup);\r\n    \r\n    if(backdrop) {\r\n        backdrop.addEventListener(\'click\', function (e) {\r\n          if (e.target === backdrop) closePopup();\r\n        });\r\n    }\r\n\r\n    document.addEventListener(\'keydown\', function (e) {\r\n      if (e.key === \'Escape\') closePopup();\r\n    });\r\n\r\n    setTimeout(openPopup, SHOW_DELAY_MS);\r\n  })();\r\n</script>',1,1),(8,'Smartsupp','Live chat, email inbox and Facebook Messenger in one customer messaging platform','/img/integrations/Smartsupp.svg','',1,1),(9,'Tawk.to','Track and chat with visitors on your website, mobile app or a free customizable page','/img/integrations/Tawk.to.svg','',1,1),(10,'Tidio','Communicator for businesses that keep live chat, chatbots, Messenger and email in one place','/img/integrations/Tidio.svg','',1,1),(11,'Zendesk Chat','Helps respond quickly to customer questions, reduce wait times and increase sales','/img/integrations/Zendesk%20Chat.svg','',1,1),(12,'Getbutton.io','Chat with website visitors through popular messaging apps. Whatsapp, messenger etc. contact button.','/img/integrations/Getbutton.svg','<!-- Custom Telegram Floating Button -->\r\n<a href=\"https://t.me/alphasmmpanel\" target=\"_blank\" class=\"telegram-button\">\r\n    <img src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/8/82/Telegram_logo.svg/2048px-Telegram_logo.svg.png\" alt=\"Telegram\">\r\n</a>\r\n\r\n<!-- CSS for Telegram Button -->\r\n<style>\r\n    /* Pulse Animation */\r\n    @keyframes pulse {\r\n        0% {\r\n            transform: scale(1);\r\n            box-shadow: 0 0 0 0 rgba(0, 136, 204, 0.5);\r\n        }\r\n        70% {\r\n            transform: scale(1.05);\r\n            box-shadow: 0 0 0 10px rgba(0, 136, 204, 0);\r\n        }\r\n        100% {\r\n            transform: scale(1);\r\n            box-shadow: 0 0 0 0 rgba(0, 136, 204, 0);\r\n        }\r\n    }\r\n\r\n    /* Telegram Button Container */\r\n    .telegram-button {\r\n        position: fixed;\r\n        bottom: 20px;\r\n        left: 20px;\r\n        width: 55px;\r\n        height: 55px;\r\n        border-radius: 50%;\r\n        overflow: hidden;\r\n        display: flex;\r\n        align-items: center;\r\n        justify-content: center;\r\n        z-index: 1000;\r\n        animation: pulse 2s infinite;\r\n        transition: transform 0.2s ease-in-out, box-shadow 0.2s ease-in-out;\r\n        padding: 0;\r\n        margin: 0;\r\n        background-color: transparent;\r\n        box-sizing: border-box;\r\n    }\r\n\r\n    /* Telegram Icon - Fully fills circle */\r\n    .telegram-button img {\r\n        width: 100%;\r\n        height: 100%;\r\n        object-fit: cover;\r\n        border-radius: 50%;\r\n        display: block;\r\n    }\r\n\r\n    /* Hover Effect */\r\n    .telegram-button:hover {\r\n        transform: scale(1.1);\r\n        box-shadow: 0 8px 20px rgba(0, 0, 0, 0.3);\r\n    }\r\n</style>',1,1),(13,'Google reCAPTCHA v2','It uses an advanced risk analysis engine and adaptive challenges to prevent malware from engaging in abusive activities on your website.','/img/integrations/reCAPTCHA.svg','',1,1),(14,'Whatsapp','Whatsapp is for Personal Support of your Users','/img/integrations/whatsapp.svg','<!--  Support Button Only -->\r\n<div class=\"support-widget\">\r\n  <a href=\"https://wa.me/8801\" target=\"_blank\" class=\"support-button\">\r\n    <i class=\"fab fa-whatsapp\"></i>\r\n  </a>\r\n</div>\r\n\r\n<style>\r\n.support-widget {\r\n  position: fixed;\r\n  bottom: 15px;\r\n  right: 15px;\r\n  z-index: 9999;\r\n}\r\n\r\n.support-button {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  border-radius: 50%;\r\n  overflow: hidden;\r\n  padding: 0;\r\n  margin: 0;\r\n  border: none;\r\n  animation: pulse 2s infinite;\r\n  cursor: pointer;\r\n  box-shadow: 0 4px 8px rgba(0,0,0,0.3);\r\n  width: 55px;\r\n  height: 55px;\r\n  background: #25D366; /* WhatsApp green */\r\n  color: white;\r\n  font-size: 28px;\r\n  text-decoration: none;\r\n}\r\n\r\n/* Hover/Click করলে রঙ একেবারেই বদলাবে না */\r\n.support-button:hover,\r\n.support-button:focus,\r\n.support-button:active {\r\n  background: #25D366 !important;\r\n  color: white !important;\r\n  box-shadow: 0 4px 8px rgba(0,0,0,0.3) !important;\r\n}\r\n</style>',1,2);
